#include <bits/stdc++.h>
#define ll long long
#define pii pair < int , int >
using namespace std;
const int N = 1e4 + 10 , M = 5e4 + 10;
//定义head数组，定义e_cnt变量
int head[ N ] , e_cnt;
//定义EDGE结构体
struct EDGE {
	int to , pre , w;
}e[ M * 2 ];
//定义add_edge函数
void add_edge( int frome , int to , int w ) {
	e[ ++e_cnt ] = EDGE{ to , head[ frome ] , w };
	head[ frome ] = e_cnt;
}
//定义优先队列
priority_queue < pii , vector < pii > , greater < pii > > heap;
//定义变量n、m、k、s、t，dis数组
int n , m , k , dis[ N ][ 15 ] , s , t;
//定义数组book
bool book[ N ][ 15 ];
//定义迪杰斯特拉最短路径函数
void dij( int p ) {
	//讲初始的初始化为0
	dis[ s ][ p ] = 0;
	//给优先队列赋值
	heap.push( make_pair( 0 , s ) );
	//循环求出第p层的最短路
	while( !heap.empty() ) {
		//定义变量u
		int u = heap.top().second;
		//讲这个值pop掉
		heap.pop();
		//判断是否走过这个节点
		if( book[ u ][ p ] ) {
			continue;
		}
		//走到这个节点
		book[ u ][ p ] = 1;
		//循环遍历
		for( int i = head[ u ] ; i ; i = e[ i ].pre ) {
			//定义变量v
			int v = e[ i ].to;
			//判断是否还有新的最短路
			if( e[ i ].w + dis[ u ][ p ] < dis[ v ][ p ] ) {
				//松弛操作，求出新的最短路
				dis[ v ][ p ] = e[ i ].w + dis[ u ][ p ];
				//查看是否比上一层短
				if( p > 0 && dis[ u ][ p - 1 ] < dis[ v ][ p ] ) {
					//松弛操作，求出新的最短路
					dis[ v ][ p ] = dis[ u ][ p - 1 ];
				}
				//更新heap
				heap.push( make_pair( dis[ v ][ p ] , v ) );
			//查看是否比上一层更短
			} else if( p > 0 && dis[ u ][ p - 1 ] < dis[ v ][ p ] ) {
				//松弛操作，求出新的最短路
				dis[ v ][ p ] = dis[ u ][ p - 1 ];
				//更新heap
				heap.push( make_pair( dis[ v ][ p ] , v ) );
			}
		}
	}
}
signed main() {
	//初始化dis数组
	memset( dis , 0x3f , sizeof( dis ) );
	//输入
	cin >> n >> m >> k >> s >> t;
	//循环遍历
	for( int i = 1 ; i <= m ; i++ ) {
		//定义变量
		int u , v , w;
		//输入
		cin >> u >> v >> w;
		//记录节点u和节点v
		add_edge( u , v , w );
		//记录节点v和节点u
		add_edge( v , u , w );
	}
	//循环遍历
	for( int i = 0 ; i <= k ; i++ ) {
		//进行求求短路操作
		dij( i );
	}
	//输出
	cout << dis[ t ][ k ];
	return 0;
}
